class Solution {
    public int minDays(int n) {
        int days = 0;
        while (n > 0) {
            if (n % 2 == 0 && n % 3 == 0) {
                n /= 6;
            } else if (n % 2 == 0) {
                n /= 2;
            } else if (n % 3 == 0) {
                n /= 3;
            } else {
                n -= 1;
            }
            days++;
        }
        return days;
    }
}

